-- Database setup for Cozy House pet adoption website

-- Create pets table
CREATE TABLE IF NOT EXISTS pets (
    id VARCHAR(255) PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    image TEXT,
    breed VARCHAR(255),
    age VARCHAR(255),
    description TEXT,
    inoculations TEXT[],
    diseases TEXT[],
    parasites TEXT[]
);

-- Insert sample data
ON CONFLICT (id) DO NOTHING;