VALUES 
('1', 'Катрин', 'pet-katrine.png', 'Британская короткошёрстная', '6 месяцев', 'Катрин — нежная и ласковая кошка, которая любит сворачиваться калачиком в солнечных местах. Она хорошо ладит с другими питомцами и детьми.', ARRAY['панлейкопения', 'ринотрахеит', 'калицивироз'], ARRAY['нет'], ARRAY['нет']),
