('10', 'Макс', 'pet-charly.png', 'Немецкая овчарка', '4 года', 'Макс — преданная и умная немецкая овчарка, которая любит защищать свою семью и играть с мячом во дворе.', ARRAY['бешенство', 'чумка', 'парвовирус'], ARRAY['нет'], ARRAY['нет']),
('11', 'Молли', 'pet-timmy.png', 'Рэгдолл', '18 месяцев', 'Молли — покладистая и спокойная кошка породы рэгдолл, которая любит, когда её носят на руках и ласкают как куклу.', ARRAY['панлейкопения', 'ринотрахеит'], ARRAY['нет'], ARRAY['нет']),
