('13', 'Зои', 'pet-freddie.png', 'Мейн-кун', '2 года', 'Зои — дружелюбная и игривая мейн-кун с впечатляющим размером и характером.', ARRAY['панлейкопения', 'калицивироз', 'ринотрахеит'], ARRAY['нет'], ARRAY['нет']),
